// // This module forwards data based on the select signal
// - When sel is 00, forward_A = A and forward_B = B
// - When sel is 01, forward_A = 0 and forward_B = B
// - When sel is 10, forward_A = A and forward_B = 0
// - When sel is 11, forward_A = 0 and forward_B = 0
module forwarding_unit (
    input [31:0] A,
    input [31:0] B,
    input [1:0] sel,
    output reg [31:0] forward_A,
    output reg [31:0] forward_B
);
    always @(*) begin
        case (sel)
            2'b00: begin
                forward_A = A;
                forward_B = B;
            end
            2'b01: begin
                forward_A = 32'b0;
                forward_B = B;
            end
            2'b10: begin
                forward_A = A;
                forward_B = 32'b0;
            end
            2'b11: begin
                forward_A = 32'b0;
                forward_B = 32'b0;
            end
            default: begin
                forward_A = 32'b0;
                forward_B = 32'b0;
            end
        endcase
    end
endmodule

